CREATE INDEX IF NOT EXISTS idx_mwiploc_equip ON mes_wip_location (current_equipment_id) WHERE current_equipment_id IS NOT NULL;

-- ---------------------------------------------------------------------------
-- MES-7.3 mes_wip_movements
