    uploaded_by             UUID            REFERENCES users(user_id),
    uploaded_at             TIMESTAMPTZ     DEFAULT now(),
    tamper_detected         BOOLEAN         DEFAULT FALSE,
    retention_years         INT             DEFAULT 5,
