DO $$ BEGIN CREATE TYPE packing_status_enum AS ENUM ('draft', 'packed', 'verified', 'shipped'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

CREATE TABLE IF NOT EXISTS packing_lists (
