CREATE INDEX IF NOT EXISTS idx_pm_plans_status ON pm_maintenance_plans (status);

CREATE TABLE IF NOT EXISTS pm_maintenance_plan_items (
    maintenance_plan_item_id    UUID            PRIMARY KEY DEFAULT uuid_generate_v4(),
