    spare_part_item_id          VARCHAR(50)     REFERENCES items(item_id),
    quantity_per                NUMERIC(12,2),
    instruction_ref             VARCHAR(100),
    is_mandatory                BOOLEAN         NOT NULL DEFAULT TRUE,
    metadata                    JSONB           DEFAULT '{}'::jsonb,
