    status                      VARCHAR(20)     NOT NULL DEFAULT 'open'
                                CHECK (status IN ('open', 'in_progress', 'completed', 'skipped')),
    metadata                    JSONB           DEFAULT '{}'::jsonb,
    created_at                  TIMESTAMPTZ     NOT NULL DEFAULT now(),
    UNIQUE (pm_work_order_id, line_number)
);
