CREATE INDEX IF NOT EXISTS idx_pm_condition_alarm ON pm_condition_monitoring (is_alarm);

CREATE TABLE IF NOT EXISTS pm_equipment_counters (
    pm_equipment_counter_id     UUID            PRIMARY KEY DEFAULT uuid_generate_v4(),
