    created_at                   TIMESTAMPTZ     NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_prj_time_entry_date ON prj_time_entries (work_date);

CREATE TABLE IF NOT EXISTS prj_cost_collections (
