    lead_status                  VARCHAR(20)     NOT NULL DEFAULT 'new'
                                 CHECK (lead_status IN ('new', 'qualified', 'disqualified', 'converted')),
    metadata                     JSONB           DEFAULT '{}'::jsonb,
