    item_id                      VARCHAR(50)     REFERENCES items(item_id),
    shipment_package_id          UUID            REFERENCES shipment_packages(package_id),
    quantity                     NUMERIC(14,2)   DEFAULT 0,
    gross_weight_kg              NUMERIC(12,2),
