    tms_carrier_id               UUID            REFERENCES tms_carriers(tms_carrier_id),
    quote_number                 VARCHAR(80)     NOT NULL UNIQUE,
    quoted_amount                NUMERIC(14,2)   NOT NULL,
    currency_code                VARCHAR(10)     DEFAULT 'USD',
