    line_number                  INT             NOT NULL,
    item_id                      VARCHAR(50)     REFERENCES items(item_id),
    price                        NUMERIC(14,4),
    minimum_order_qty            NUMERIC(14,2),
    lead_time_days               INT,
    service_level_pct            NUMERIC(6,2),
