    recommended_vendor_id        VARCHAR(50)     REFERENCES vendors(vendor_id),
    approved_by                  UUID            REFERENCES users(user_id),
    notes                        TEXT,
    metadata                     JSONB           DEFAULT '{}'::jsonb,
    created_at                   TIMESTAMPTZ     NOT NULL DEFAULT now()
);

