CREATE TABLE IF NOT EXISTS srm_supplier_risk_events (
    srm_supplier_risk_event_id   UUID            PRIMARY KEY DEFAULT uuid_generate_v4(),
    vendor_id                    VARCHAR(50)     NOT NULL REFERENCES vendors(vendor_id),
