);

CREATE TABLE IF NOT EXISTS fixture_master (
    fixture_id                   UUID            PRIMARY KEY DEFAULT uuid_generate_v4(),
    fixture_code                 VARCHAR(80)     NOT NULL UNIQUE,
    fixture_name                 VARCHAR(200)    NOT NULL,
