    item_id                      VARCHAR(50)     REFERENCES items(item_id),
    material_cost                NUMERIC(14,2)   DEFAULT 0,
    labor_cost                   NUMERIC(14,2)   DEFAULT 0,
    overhead_cost                NUMERIC(14,2)   DEFAULT 0,
