CREATE TABLE IF NOT EXISTS fin_budget_versions (
    fin_budget_version_id        UUID            PRIMARY KEY DEFAULT uuid_generate_v4(),
    budget_code                  VARCHAR(50)     NOT NULL UNIQUE,
