CREATE OR REPLACE FUNCTION set_row_version()
RETURNS TRIGGER AS $$
BEGIN
    NEW.row_version = COALESCE(OLD.row_version, 0) + 1;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

