CREATE TABLE IF NOT EXISTS ipqc_inspections (
    ipqc_inspection_id           UUID            PRIMARY KEY DEFAULT uuid_generate_v4(),
    ipqc_number                  VARCHAR(50)     NOT NULL UNIQUE,
